head.script:
//-------------------------------------------------------------------------
// 전역변수 선언
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.globalVars();
    scwin.f_OnLoad();
    // 테스트 데이터
    // ed_retrieveDate.setValue("201604");
};



/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {

    const sDate = $c.date.getServerDateTime('yyyyMMdd')
    scwin.retrieveDate = sDate.slice(0, 6);	 // 현재년월을 구한다.
    scwin.strFromDate = scwin.retrieveDate;

    const userInfo = $c.data.getMemInfo();
    scwin.userId = userInfo.userId;

    scwin.sView = $c.data.getParameter('sView') ?? ''; //싱글뷰에서 넘어온값

    scwin.fromDate = "";			// 작업날짜+++
    scwin.orgObjCdHidVal = "";
    scwin.orgObjNmHidVal = "";

    scwin.realColID = {}; // 컬럼ID 추적

};



/* 조회 TR EVENT(성공) */
scwin.sbm_retrieve_submitdone = function (e) {

    scwin.f_Pattern();

    // OnLoadCompleted(rowCnt)
    let rowCnt = ds_Result.getTotalRow();
    totalRows.setValue(rowCnt);

    if (rowCnt == 0) {
        ds_Result.removeAll();
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    };

};



//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = function () {

    ed_retrieveDate.setValue(scwin.retrieveDate);
    co_ds_combo1.action = '/ps.co.RetrievePsCboCmmCMD.do?' +
        'cmd=retrieveUserpattern&' +
        'strVal=' + scwin.userId;
    $c.sbm.execute(co_ds_combo1); // 컴포넌트로 설정


    if (scwin.sView == "Y") {
        ed_retrieveDate.setValue(scwin.strFromDate);
        ed_acctDeptCd.setValue('00047');
        scwin.f_CheckPopUp(ed_acctDeptCd, ed_acctDeptNm, '1', 'CD');
        scwin.f_Retrieve();
    };

};


scwin.f_Pattern = async function () {

    let colVal = acb_userpattern.getValue()
    if (colVal == "") return;
    let userID = scwin.userId;
    sbm_ds_Header.action = "/ds.fs.distaccheck.distributionMgnt.RetrievePatternByUserCMD.do?" +
        "userpattern=" + acb_userpattern.getValue() +
        "&regId=" + userID;
    await $c.sbm.execute(sbm_ds_Header);

    // 컬럼 숨기기
    let colCnt = gr_result.getTotalCol();
    for (let i = 0; i < colCnt; i++) {
        gr_result.setColumnVisible(i, false);
    };

    // 그리드 초기화
    ds_realGrid.removeAll();
    scwin.realColID = {};

    // 컬럼세팅
    let colTotCnt = ds_Header.getTotalRow();
    let colIdArray = [];
    for (let i = 0; i < colTotCnt; i++) {
        let showColId = ds_Header.getCellData(i, "cdEngNm");
        colIdArray.push(showColId);

        // 그리드 헤더 값, 넓이, 정렬
        let colInfo = [];

        // headerVal
        switch (showColId) {
            case "acctCd":
            case "acctNm":
                colInfo = ["계정명", "100", "center"];
                break;

            case "headcomCd": colInfo = ["본사/지사", "100", "center", 'text']; break;
            case "coClsCd": colInfo = ["관계사/타사", "50", "center", 'text']; break;
            case "newCtrtYr": colInfo = ["계약년도", "100", "center", 'text']; break;
            case "upperClntNo": colInfo = ["그룹거래처", "80", "center", 'text']; break;
            case "upperClntNm": colInfo = ["그룹거래처명", "100", "left", 'text']; break;
            case "bilgClntNo": colInfo = ["청구거래처", "90", "center", 'text']; break;
            case "bilgClntNm": colInfo = ["청구거래처명", "140", "left", 'text']; break;
            case "ctrtNo": colInfo = ["계약번호", "100", "center", 'text']; break;
            case "ctrtEmpNm": colInfo = ["계약<br/>담당자", "60", "center", 'text']; break;
            case "bizDomNm": colInfo = ["사업영역", "70", "center", 'text']; break;
            case "sellLodeptCd": colInfo = ["매출귀속<br/>부서코드", "80", "center", 'text']; break;
            case "sellLodeptNm": colInfo = ["매출귀속<br/>부서명", "120", "left", 'text']; break;
            case "cargoClsCd": colInfo = ["화물구분", "70", "center", 'text']; break;
            case "cargoType": colInfo = ["대표화종", "140", "left", 'text']; break;
            case "ttAmt": colInfo = ["합계", "80", "right", 'number']; break;
            case "pchsAmt": colInfo = ["확정<br/>매입액", "80", "right", 'number']; break;
            case "unSellAmtThis": colInfo = ["미확정<br/>매출액", "80", "right", 'number']; break;
            case "innerSellAmt": colInfo = ["내부매출", "80 ", "right", 'number']; break;
            case "innerPchsAmt": colInfo = ["내부매입", "80", "right", 'number']; break;
            case "sellAmt": colInfo = ["확정<br/>매출액", "80", "right", 'number']; break;
            case "unPchsAmtThis": colInfo = ["미확정<br/>매입액", "80", "right", 'number']; break;
            case "sellTotAmt": colInfo = ["매출<br/>합계", "80", "right", 'number']; break;
            case "pchsTotAmt": colInfo = ["매입<br/>합계", "80", "right", 'number']; break;
            case "pchsVarAmt": colInfo = ["매입합<br/>(변동비)", "80", "right", 'number']; break;
            case "pchsFixAmt": colInfo = ["매입합<br/>(고정비)", "80", "right", 'number']; break;
            case "selpchItemCd": colInfo = ["매출항목<br/>코드", "80", "left", 'text']; break;
            case "selpchItemNm": colInfo = ["매출항목", "100", "left", 'text']; break;
            case "acctDeptCd": colInfo = ["계약부서<br/>코드", "70", "left", 'text']; break;
            case "acctDeptNm": colInfo = ["계약부서<br/>명", "100", "left", 'text']; break;
            case "opntDeptCd": colInfo = ["상대부서<br/>코드", "70", "left", 'text']; break;
            case "opntDeptNm": colInfo = ["상대부서<br/>명", "100", "left", 'text']; break;
            case "upperDeptCd": colInfo = ["상위지사", "70", "left", 'text']; break;
            case "upperDeptNm": colInfo = ["지사명", "100", "left", 'text']; break;
            default: break;
        };

        let headerId = gr_result.getHeaderID(i);

        gr_result.setHeaderValue(headerId, colInfo[0]); // 헤더값 설정
        gr_result.setColumnWidth(headerId, colInfo[1]); // 컬럼 넓이
        gr_result.setColumnStyle(i, "text-align", colInfo[2]); // 컬럼 정렬
        gr_result.setDataType(i, colInfo[3]); // 컬럼 데이터 타입


        if (colInfo.length != 0) {
            gr_result.setColumnVisible(i, true);
            scwin.realColID['col' + (i + 1)] = showColId; // 실제 컬럼 ID
            gr_result.setFooterDisplayFormat('col' + (i + 1),)
        };

        gr_result.setColumnVisible('distAmt', chk_distCdYn.getValue() == '1');

    };

    // 그리드 데이터 세팅
    let allData = ds_Result.getAllJSON();
    let gridDataArray = [];
    let sortCol = '';
    for (let i = 0; i < allData.length; i++) {
        let rowData = allData[i];
        let rowObj = {};
        rowObj['realIdx'] = i;

        for (let j = 0; j < colIdArray.length; j++) {
            let colId = colIdArray[j];
            let colCnt = j + 1;
            rowObj["col" + colCnt] = rowData[colId];
        };

        gridDataArray.push(rowObj);
    };


    ds_realGrid.setJSON(gridDataArray);
    ds_realGrid.multisort({
        sortIndex: 'col1 col2',
        sortOrder: '1 1'
    })
    let sortGridData = ds_realGrid.getAllJSON()

    ds_realGrid.setJSON(sortGridData);


    // footer데이터 설정
    for (let i = 0; i < colTotCnt; i++) {
        if (!gr_result.getColumnVisible(i)) continue;

        let validColID = [
            'ttAmt', 'pchsAmt', 'unSellAmtThis',
            'innerSellAmt', 'innerPchsAmt', 'sellAmt', 'unPchsAmtThis',
            'sellTotAmt', 'pchsTotAmt', 'pchsVarAmt', 'pchsFixAmt',
        ];

        let colID = 'col' + (i + 1);
        if (!validColID.includes(scwin.realColID[colID])) return '';

        let sumVal = gr_result.getExpressionValue(`SUM('${colID}')`);

        gr_result.setFooterValue(colID + 'Footer', $c.num.formatNumber(sumVal));
    };


};


//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->거래처 , 2:조회->귀속부서
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, flag) {

    let param_yy = ed_retrieveDate.getValue().trim();

    // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.  
    let cd = "", nm = "";
    if (flag != "ALL") {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    };

    //자회사 포함 부서조회
    let popUpText = 'retrieveAcctDeptCdInfo5';
    if (param_yy.slice(0, 4) == '2006') {
        popUpText = 'retrieveAcctDeptCdInfoBef';
    };
    udc_comCode.setSelectId(popUpText); // 추가

    switch (select_code) {
        case '1':
            udc_comCode.cfCommonPopUp(
                scwin.f_resultPopUp, cd, nm, "T",
                null, null, "450", null,
                null, null, null, null, null,
                null, null, null, null, null, param_yy
            );
            break;
        default:
            $c.gus.cfAlertMsg("잘못된 Function 호출 입니다. 관리자에게 문의하시기 바랍니다.");
            break;
    };

};


//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {

    if (flag == "CD") {
        if (orgObjCd.getValue() == scwin.orgObjCdHidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        };
    } else {
        if (orgObjNm.getValue() == scwin.orgObjNmHidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        };
    };

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        };
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        scwin.orgObjCdHidVal = "";
    };

};


//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopUp = function (rtnList) {

    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_acctDeptCd.setValue(rtnList[0]);	// 코드값
        ed_acctDeptNm.setValue(rtnList[1]);	// 코드명
        scwin.orgObjCdHidVal = rtnList[0];	// HIDDEN 코드값
        scwin.orgObjNmHidVal = rtnList[1];	// HIDDEN 코드명        
    } else {
        ed_acctDeptCd.setValue("");	// 코드값
        ed_acctDeptNm.setValue("");	// 코드명
        scwin.orgObjCdHidVal = "";	// HIDDEN 코드값
        scwin.orgObjNmHidVal = "";	// HIDDEN 코드명   
    };

}


//-------------------------------------------------------------------------
// 배부반영여부 체크설정
//-------------------------------------------------------------------------
scwin.f_chkYn = function () {

    if (chk_distCdYn.getValue() == '1') {
        gr_result.setColumnVisible('distAmt', true);
    } else {
        gr_result.setColumnVisible('distAmt', false);
    };

}


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {

    if (!await $c.gus.cfValidate([ed_retrieveDate, ed_acctDeptCd])) return;

    //실적월, 회계부서 validate 체크
    let jsonData = {
        "retrieveDate": ed_retrieveDate.getValue(),
        "acctDeptCd": ed_acctDeptCd.getValue(),
        "regId": scwin.userId,
        "userpattern": acb_userpattern.getValue(),
    };
    dma_retrieve.setJSON(jsonData);

    $c.sbm.execute(sbm_retrieve);

};

// f_grdHeiht 실행 후 확인
//-------------------------------------------
// 그리드 데이터 엑셀로 다운
//-------------------------------------------
scwin.f_runExcel = async function () {

    let totCnt = ds_Result.getTotalRow();

    if (totCnt == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    };

    const retConfirm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (!retConfirm) return;

    let sheetTitle = "거래처별손익실적집계";
    const options = { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle };
    $c.data.downloadGridViewExcel(gr_result, options);

};



//-------------------------------------------------------------------------
// 컴포넌트 이벤트
//-------------------------------------------------------------------------

scwin.udc_comCode_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_acctDeptCd, ed_acctDeptNm, '1', 'ALL');
};


scwin.oncelldblclick = function (rowIndex, columnIndex, columnId) {

    let arrParent = new Array();

    arrParent[0] = ed_retrieveDate.getValue();
    arrParent[1] = ed_acctDeptCd.getValue();
    arrParent[2] = "NODATA";
    arrParent[3] = "NODATA";
    arrParent[4] = "NODATA";
    arrParent[5] = "NODATA";
    arrParent[6] = "NODATA";
    arrParent[7] = "NODATA";
    arrParent[8] = "NODATA";
    arrParent[9] = "NODATA";
    arrParent[10] = "NODATA";
    arrParent[11] = "NODATA";
    arrParent[12] = "NODATA";
    arrParent[13] = "NODATA";
    arrParent[14] = "NODATA";
    arrParent[15] = "NODATA";
    arrParent[16] = "NODATA";
    arrParent[17] = "NODATA";
    arrParent[18] = "NODATA";
    arrParent[19] = "NODATA";
    arrParent[20] = "NODATA";
    arrParent[21] = "NODATA";
    arrParent[22] = "NODATA";
    arrParent[23] = "NODATA";
    arrParent[25] = "NODATA"; //fs_300_01_04b.jsp에서 사용

    const totalRow = ds_Header.getTotalRow();
    const realIdx = ds_realGrid.getCellData(rowIndex, 'realIdx');
    const targetData = ds_Result.getRowJSON(realIdx);
    const COLUMN_MAP = {
        "bilgClntNo": 2, "acctCd": 3, "acctNm": 4, "sellLodeptCd": 5,
        "sellLodeptNm": 6, "ctrtNo": 7, "bilgClntNm": 8, "headcomCd": 9,
        "coClsCd": 10, "newCtrtYr": 11, "upperClntNo": 12, "upperClntNm": 13,
        "ctrtEmpNm": 14, "bizDomNm": 15, "cargoClsCd": 16, "cargoType": 17,
        "acctDeptCd": 18, "acctDeptNm": 19, "opntDeptCd": 20, "opntDeptNm": 21,
        "upperDeptCd": 22, "upperDeptNm": 23
    };

    for (let i = 0; i < totalRow; i++) {
        const colId = ds_Header.getCellData(i, "cdEngNm");
        const targetIdx = COLUMN_MAP[colId]; // 매핑된 인덱스 찾기

        if (targetIdx !== undefined) {
            arrParent[targetIdx] = targetData[colId];
        };
    };


    // 배부반영여부
    scwin.chk_distCdYn_onchange();

    let v_url = "/ui/ds/fs/distaccheck/fs_300_01_03p.xml";
    let opts = {
        id: "pupup",
        popupName: "거래처별 손익 집계-상세-",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 500,
        title: "거래처별 손익 집계-상세-"
    };

    $c.win.openPopup(v_url, opts, arrParent);

};


/* 귀속부서코드 */
scwin.udc_comCode_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_acctDeptCd, ed_acctDeptNm, '1', 'CD');
};


/* 귀속부서명 */
scwin.udc_comCode_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_acctDeptCd, ed_acctDeptNm, '1', 'NM');
};


scwin.acb_userpattern_onviewchange = function (info) {
    scwin.f_Retrieve();
};

scwin.chk_distCdYn_onchange = function (info) {
    scwin.f_chkYn()
};



scwin.gridFormat = function (data, formattedData, rowIndex, colIndex) {

    let colID = gr_result.getColumnID(colIndex);
    let numValid = $c.num.isNumber(data);
    let validColID = [
        'ttAmt', 'pchsAmt', 'unSellAmtThis',
        'innerSellAmt', 'innerPchsAmt', 'sellAmt', 'unPchsAmtThis',
        'sellTotAmt', 'pchsTotAmt', 'pchsVarAmt', 'pchsFixAmt',
    ];

    if (data == "") return data;

    if (!validColID.includes(scwin.realColID[colID])) return formattedData;

    if (numValid) {
        return $c.num.formatNumber(data);
    } else {
        return formattedData;
    };

};
